function [pImg,satL] = fNmnlImgPrc(fNam,bg,xRay,camClb)%% Nominal Image Processing%% [pImg,satL] = fNominalImgPrc(fNam,bg,xRay)%% fNam:     file path% bg:       bg% xRay:     1x4 array, [fct,pit,minX,itr]%   fct:    factor to take out the point%   pit:    depth of the pit%   minX:   minimun counts to be taken%   itr:    number of iteration% camClb: structure of calibration for bella magspec cameras%   .fov: field of view [mm]%   .yOffset: y offset for roi [pixel]%   .height: height of image [pixel]%   .xOffset: x offset for roi [pixel]%   .width: width of image [pixel]%   .leftPos: left position of image [mm]%   .yCnter: y center pixel%   .ySt,yEd: y start and end for analysis ROI%   .xSt,xEd: x start and end for analysis ROI%   .rot: rotation [deg]%% pImg:   processed image% satL:     saturation logic%% Kei Nakamura% 2020/3/24: Created%%% input and initialization[img,~] = f12bitPngOpnV04(fNam);    % read imagesatL = max(max(img))==4096;    % saturation logic% roipImg = img(camClb.ySt:camClb.yEd,camClb.xSt:camClb.xEd);bg = bg(camClb.ySt:camClb.yEd,camClb.xSt:camClb.xEd);pImg(:,:) = fTrexTonyBgV01(pImg,bg); % background subtrpImg(:,:) = fXrayOutV10(pImg,xRay);   % xray filter        pImg(:,:) = fImageRotV02(pImg,camClb.rot,[camClb.xCntr,camClb.yCntr]);
